pragma solidity ^0.8.4;

import { IERC20 } from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import { ReentrancyGuard } from "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";
import { SafeMath } from "@openzeppelin/contracts/utils/math/SafeMath.sol";
import "@openzeppelin/contracts/security/Pausable.sol";
import "./GovStakingStorage.sol";

interface govERC20 {
    function mint(address to_, uint256 amount_) external;
}

interface ICommunityRewardsManager {
    function updateAllRewards(address account) external;

    function getAllRewards(address account) external;
}

contract GovStaking is Ownable, ReentrancyGuard, Pausable {
    uint256 public opt1 = 0;
    uint256 public opt2 = 604800; 
    uint256 public opt3 = 2629746; 
    uint256 public opt4 = 15778476; 
    uint256 public opt5 = 31556952; 
    uint256 public opt6 = 94608000; 

    mapping(uint256 => uint256) public rewardRates; 

    IERC20 public gogo;
    govERC20 public govGogo;
    GovStakingStorage public store;
    ICommunityRewardsManager public rewards;

    struct RewardRate {
        uint256 period;
        uint256 rate;
    }

    constructor(
        address storageAddress,
        address gogoAddress,
        address govGogoAddress,
        address communityRewardsManager
    ) {
        store = GovStakingStorage(storageAddress);
        gogo = IERC20(gogoAddress);
        govGogo = govERC20(govGogoAddress);
        rewards = ICommunityRewardsManager(communityRewardsManager);


        rewardRates[opt1] = 1; 
        rewardRates[opt2] = 1653439154;

        rewardRates[opt3] = 2471721604;

        rewardRates[opt4] = 4119536006;

        rewardRates[opt5] = 6971522471;

        rewardRates[opt6] = 8984441062;

    }

    event Enter(address indexed user, uint256 amount, uint256 extendingPeriod);
    event Leave(address indexed user, uint256 amount);
    event Claim(address indexed user, uint256 amount);
    event NewManager(address indexed oldAddress, address indexed newAddress);

    function enter(uint256 amount, uint256 extendingPeriod)
        external
        nonReentrant
        whenNotPaused
        returns (GovStakingStorage.UserInfo memory)
    {
        rewards.updateAllRewards(msg.sender);
        require(rewardRates[extendingPeriod] > 0, "wrong period");
        require(amount > 0 || extendingPeriod > 0, "invalid input");

        gogo.transferFrom(msg.sender, address(store), amount);
        GovStakingStorage.UserInfo memory user = store.getUserInformation(
            msg.sender
        );

        uint256 oldRate = user.rewardRate;

        if (user.amount == 0) {

            user.lockPeriod = extendingPeriod;
            user.lastClaimed = block.timestamp;
            user.rewardRate = rewardRates[extendingPeriod];
            store.addRewardMultiplier( 
                msg.sender,
                user.rewardRate,
                extendingPeriod,
                amount
            );
        } else {

            if (user.lockStart + user.lockPeriod <= block.timestamp) {
                store.removeRewardMultiplier(msg.sender);
                user.unclaimedAmount = getClaimAmount(
                    user,
                    user.lockStart + user.lockPeriod
                );
                user.lastClaimed = block.timestamp;
                user.rewardRate = rewardRates[extendingPeriod];
                user.lockPeriod = extendingPeriod;
                store.addRewardMultiplier( 
                    msg.sender,
                    user.rewardRate,
                    user.lockPeriod,
                    user.amount + amount
                );
            } else {

                uint256 oldPeriod = user.lockPeriod;
                user.unclaimedAmount = getClaimAmount(user, block.timestamp);
                user.lastClaimed = block.timestamp;
                uint256 rewardRate = getRewardForExtend(
                    msg.sender,
                    extendingPeriod,
                    amount,
                    oldRate
                );

                user.rewardRate = rewardRate;
                user.lockPeriod =
                    ((user.lockStart + user.lockPeriod) - block.timestamp) +
                    extendingPeriod;

                store.updateRewardMultiplier( 
                    msg.sender,
                    oldRate,
                    user.rewardRate,
                    block.timestamp - user.lockStart,
                    oldPeriod,
                    user.lockPeriod,
                    user.amount,
                    user.amount + amount
                );
            }
        }

        user.amount += amount;
        user.lockStart = block.timestamp;
        storeUser(user);
        store.updateRewardRate(oldRate, user.rewardRate);
        store.addLockedGogo(amount);

        emit Enter(msg.sender, amount, extendingPeriod);

        return user;
    }

    function leave() external nonReentrant whenNotPaused {
        rewards.updateAllRewards(msg.sender);
        GovStakingStorage.UserInfo memory user = store.getUserInformation(
            msg.sender
        );
        require(
            block.timestamp >= user.lockPeriod + user.lockStart,
            "tokens are still locked"
        );
        _claim();
        rewards.getAllRewards(msg.sender);
        uint256 amount = user.amount;

        store.removeLockedGogo(amount);
        store.removeRewardRate(user.rewardRate);
        store.removeUser(msg.sender);

        store.transferGogo(msg.sender, amount);

        emit Leave(msg.sender, amount);
    }

    function _claim() internal {
        GovStakingStorage.UserInfo memory user = store.getUserInformation(
            msg.sender
        );
        uint256 qualifiedUntil = (
            user.lockStart + (user.lockPeriod) < block.timestamp
                ? user.lockStart + user.lockPeriod
                : block.timestamp
        );

        uint256 toClaim = getClaimAmount(user, qualifiedUntil) +
            user.unclaimedAmount;

        user.unclaimedAmount = 0;
        user.lastClaimed = qualifiedUntil;

        storeUser(user);
        if (toClaim > 0) govGogo.mint(msg.sender, toClaim);

        emit Claim(msg.sender, toClaim);
    }


    function claim() public nonReentrant whenNotPaused {
        rewards.updateAllRewards(msg.sender);
        _claim();
    }


    function claimAll() public nonReentrant whenNotPaused {
        rewards.updateAllRewards(msg.sender);
        _claim();
        rewards.getAllRewards(msg.sender);
    }

    function getRewardForExtend(
        address account,
        uint256 extendingPeriod,
        uint256 amount,
        uint256 oldRate
    ) public view returns (uint256) {
        GovStakingStorage.UserInfo memory user = store.getUserInformation(
            account
        );

        return
            extendingPeriod > 0
                ? calcExtendRate( 
                    user.lockPeriod,
                    user.lockPeriod - (block.timestamp - user.lockStart),
                    oldRate,
                    getRewardRate(user.lockPeriod + extendingPeriod)
                )
                : calcRate( 
                    user.amount,
                    amount,
                    oldRate,
                    getRewardRate(
                        user.lockStart + user.lockPeriod - block.timestamp
                    )
                );
    }

    function storeUser(GovStakingStorage.UserInfo memory user) internal {
        store.writeUser(
            msg.sender,
            user.amount,
            user.lockStart,
            user.lockPeriod,
            user.lastClaimed,
            user.unclaimedAmount,
            user.rewardRate
        );
    }

    function getRewardRate(uint256 period) internal view returns (uint256) {
        if (rewardRates[period] > 0) return rewardRates[period];
        if (period > opt6) return rewardRates[opt6]; 

        uint256 min = 0;
        uint256 max = 0;

        if (period >= opt1 && period <= opt2) {
            min = opt1;
            max = opt2;
        }
        if (period >= opt2 && period <= opt3) {
            min = opt2;
            max = opt3;
        }
        if (period >= opt3 && period <= opt4) {
            min = opt3;
            max = opt4;
        }
        if (period >= opt4 && period <= opt5) {
            min = opt4;
            max = opt5;
        }
        if (period >= opt5 && period <= opt6) {
            min = opt5;
            max = opt6;
        }

        return
            (((rewardRates[max] - rewardRates[min]) * (period - min)) /
                (max - min)) + rewardRates[min];
    }


    function earned() public view returns (uint256) {
        GovStakingStorage.UserInfo memory user = store.getUserInformation(
            msg.sender
        );
        uint256 qualifiedUntil = (
            user.lockStart + (user.lockPeriod) < block.timestamp
                ? user.lockStart + user.lockPeriod
                : block.timestamp
        );

        return getClaimAmount(user, qualifiedUntil) + user.unclaimedAmount;
    }

    function getClaimAmount(
        GovStakingStorage.UserInfo memory user,
        uint256 timestamp
    ) internal pure returns (uint256) {
        return ((timestamp - user.lastClaimed) *
            (user.amount / 1e18) *
            (user.rewardRate));
    }

    function calcRate(
        uint256 amount1,
        uint256 amount2,
        uint256 rate1,
        uint256 rate2
    ) internal pure returns (uint256) {
        return ((rate1 * amount1) + (rate2 * amount2)) / (amount1 + amount2);
    }

    function calcExtendRate(
        uint256 t1,
        uint256 t2,
        uint256 r1,
        uint256 r2
    ) internal pure returns (uint256) {
        return ((r2 - r1) * ((t2 * 1e18) / t1)) / 1e18 + r1;
    }

    function setRewardRate(uint256 period, uint256 newRate) external onlyOwner {
        require(rewardRates[period] > 0, "wrong period");
        rewardRates[period] = newRate;
    }

    function setRewardRates(RewardRate[] memory rates) external onlyOwner {
        for (uint256 i = 0; i < rates.length; i++) {
            if (rewardRates[rates[i].period] > 0)
                rewardRates[rates[i].period] = rates[i].rate;
        }
    }

    function setCommunityManager(address newManager) external onlyOwner {
        rewards = ICommunityRewardsManager(newManager);
    }

    function setStorage(address newStorage) external onlyOwner {
        store = GovStakingStorage(newStorage);
    }

    function pause() public onlyOwner {
        _pause();
    }

    function unpause() public onlyOwner {
        _unpause();
    }
}

pragma solidity ^0.6.12;


import "./libraries.sol"

interface IWETH {
    function deposit() external payable;
    function transfer(address to, uint value) external returns (bool);
    function withdraw(uint) external;
}

interface IHedgeySwap {
    function hedgeySwap(address payable originalOwner, uint _c, uint totalPurchase, address[] memory path, bool cashBack) external;
}


interface IHedgey {
    function asset() external view returns (address asset);
    function pymtCurrency() external view returns (address pymtCurrency);
    function exercise(uint _c) external payable;

}



contract HedgeyAnySwap is ReentrancyGuard {
    using SafeMath for uint;
    using SafeERC20 for IERC20;


    address public factory;
    address payable public weth;
    uint8 public fee;

    constructor(address _factory, uint8 _fee, address payable _weth) public {
        factory = _factory;
        weth = _weth;
        fee = _fee;
    }




    receive() external payable {    
    }



    function sortTokens(address tokenA, address tokenB) internal view returns (address token0, address token1) {
        require(tokenA != tokenB, 'UniswapV2Library: IDENTICAL_ADDRESSES');
        (token0, token1) = tokenA < tokenB ? (tokenA, tokenB) : (tokenB, tokenA);
        require(token0 != address(0), 'UniswapV2Library: ZERO_ADDRESS');
    }

    function getAmountOut(uint amountIn, uint reserveIn, uint reserveOut) public view returns (uint amountOut) {
        require(amountIn > 0, 'UniswapV2Library: INSUFFICIENT_INPUT_AMOUNT');
        require(reserveIn > 0 && reserveOut > 0, 'UniswapV2Library: INSUFFICIENT_LIQUIDITY');
        uint amountInWithFee = amountIn.mul(10000 - fee);
        uint numerator = amountInWithFee.mul(reserveOut);
        uint denominator = reserveIn.mul(10000).add(amountInWithFee);
        amountOut = numerator / denominator;
    }


    function getAmountIn(uint amountOut, uint reserveIn, uint reserveOut) public view returns (uint amountIn) {
        require(amountOut > 0, 'UniswapV2Library: INSUFFICIENT_OUTPUT_AMOUNT');
        require(reserveIn > 0 && reserveOut > 0, 'UniswapV2Library: INSUFFICIENT_LIQUIDITY');
        uint numerator = reserveIn.mul(amountOut).mul(10000);
        uint denominator = reserveOut.sub(amountOut).mul(10000 - fee);
        amountIn = (numerator / denominator).add(1);
    }


    function getAmountsOut(uint amountIn, address[] memory path) public view returns (uint[] memory amounts) {
        require(path.length >= 2, 'UniswapV2Library: INVALID_PATH');
        amounts = new uint[](path.length);
        amounts[0] = amountIn;
        for (uint i; i < path.length - 1; i++) {
            (uint reserveIn, uint reserveOut) = getReserves(path[i], path[i + 1]);
            amounts[i + 1] = getAmountOut(amounts[i], reserveIn, reserveOut);
        }
    }


    function getAmountsIn(uint amountOut, address[] memory path) public view returns (uint[] memory amounts) {
        require(path.length >= 2, 'UniswapV2Library: INVALID_PATH');
        amounts = new uint[](path.length);
        amounts[amounts.length - 1] = amountOut;
        for (uint i = path.length - 1; i > 0; i--) {
            (uint reserveIn, uint reserveOut) = getReserves(path[i - 1], path[i]);
            amounts[i - 1] = getAmountIn(amounts[i], reserveIn, reserveOut);
        }
    }




    function getReserves(address tokenA, address tokenB) public view returns (uint reserveA, uint reserveB) {
        (address token0,) = sortTokens(tokenA, tokenB);
        address pair = IUniswapV2Factory(factory).getPair(tokenA, tokenB);
        (uint reserve0, uint reserve1,) = IUniswapV2Pair(pair).getReserves();
        (reserveA, reserveB) = tokenA == token0 ? (reserve0, reserve1) : (reserve1, reserve0);
    }




    function swap(bool send, address tokenIn, address tokenOut, uint _in, uint out, address to) internal {
        address pair = IUniswapV2Factory(factory).getPair(tokenIn, tokenOut);
        if (send) SafeERC20.safeTransfer(IERC20(tokenIn), pair, _in); 
        address token0 = IUniswapV2Pair(pair).token0();
        if (tokenIn == token0) {
            IUniswapV2Pair(pair).swap(0, out, to, new bytes(0));
        } else {
            IUniswapV2Pair(pair).swap(out, 0, to, new bytes(0));
        }

    }


    function multiSwap(address[] memory path, uint amountOut, uint amountIn, address to) internal {
       require(path.length >= 2, 'UniswapV2Library: INVALID_PATH');
       require((amountOut > 0 && amountIn == 0) || (amountIn > 0 && amountOut == 0), "one of the amounts must be 0");
       uint[] memory amounts = (amountOut > 0) ? getAmountsIn(amountOut, path) : getAmountsOut(amountIn, path);
       for (uint i = 0; i < path.length - 1; i++) {
           address _to = (i < path.length - 2) ? IUniswapV2Factory(factory).getPair(path[i+1], path[i+2]) : to;
           swap((i == 0), path[i], path[i+1], amounts[i], amounts[i+1], _to);
       }
    }





    function flashSwap(address borrowedToken, address tokenDue, uint out, bytes memory data) internal {
        address pair = IUniswapV2Factory(factory).getPair(borrowedToken, tokenDue);
        address token0 = IUniswapV2Pair(pair).token0();
        if (borrowedToken == token0) {
            IUniswapV2Pair(pair).swap(0, out, address(this), data);
        } else {
            IUniswapV2Pair(pair).swap(out, 0, address(this), data);
        }
    }


    function uniswapV2Call(address sender, uint amount0, uint amount1, bytes memory data) external {

        address token0 = IUniswapV2Pair(msg.sender).token0(); 
        address token1 = IUniswapV2Pair(msg.sender).token1(); 
        (uint reserveA, uint reserveB) = getReserves(token0, token1);
        assert(msg.sender == IUniswapV2Factory(factory).getPair(token0, token1));
        (address payable _hedgey, uint _n, address[] memory path, bool optionType) = abi.decode(data, (address, uint, address[], bool));

        uint amountDue = amount0 == 0 ? getAmountIn(amount1, reserveA, reserveB) : getAmountIn(amount0, reserveB, reserveA);
        uint purchase = amount0 == 0 ? amount1 : amount0;
        if (optionType) {
            (address asset) = exerciseCall(_hedgey, _n, purchase); 

            multiSwap(path, amountDue, 0, msg.sender);
        } else {

            (address paymentCurrency) = exercisePut(_hedgey, _n, purchase);

            multiSwap(path, amountDue, 0, msg.sender);
        }


    }



    function exerciseCall(address payable hedgeyCalls, uint _c, uint purchase) internal returns (address asset) {

        if(IHedgey(hedgeyCalls).pymtCurrency() == weth) {

            IWETH(weth).withdraw(purchase);
            IHedgey(hedgeyCalls).exercise{value: purchase}(_c); 
        } else {
            SafeERC20.safeIncreaseAllowance(IERC20(IHedgey(hedgeyCalls).pymtCurrency()), hedgeyCalls, purchase);
            IHedgey(hedgeyCalls).exercise(_c);
        }


        asset = IHedgey(hedgeyCalls).asset();
    }


    function exercisePut(address payable hedgeyPuts, uint _p, uint sale) internal returns (address paymentCurrency) {
        if(IHedgey(hedgeyPuts).asset() == weth) {

            IWETH(weth).withdraw(sale);
            IHedgey(hedgeyPuts).exercise{value: sale}(_p);
        } else {
            SafeERC20.safeIncreaseAllowance(IERC20(IHedgey(hedgeyPuts).asset()), hedgeyPuts, sale); 
            IHedgey(hedgeyPuts).exercise(_p);
        }

        paymentCurrency = IHedgey(hedgeyPuts).pymtCurrency();

    }


    function hedgeyCallSwap(address payable originalOwner, uint _c, uint totalPurchase, address[] memory path, bool cashBack) external payable nonReentrant {



        address[] memory _path = new address[](path.length - 1);
        for (uint i; i < path.length - 1; i++) {
            _path[i] = path[i];
        }
        bytes memory data = abi.encode(msg.sender, _c, _path, true);
        flashSwap(path[path.length - 2], path[path.length - 1], totalPurchase, data);

        if(cashBack) {

            if(IHedgey(msg.sender).pymtCurrency() == weth) {
                multiSwap(path, 0, IERC20(path[0]).balanceOf(address(this)), address(this)); 

                uint wethBalance = IERC20(weth).balanceOf(address(this));
                IWETH(weth).withdraw(wethBalance);
                originalOwner.transfer(wethBalance);
            } else {
                multiSwap(path, 0, IERC20(path[0]).balanceOf(address(this)), originalOwner);
            }

        } else {
            if(IHedgey(msg.sender).asset() == weth) {
                uint wethBalance = IERC20(weth).balanceOf(address(this));
                IWETH(weth).withdraw(wethBalance);
                originalOwner.transfer(wethBalance);
            } else {
                SafeERC20.safeTransfer(IERC20(path[0]), originalOwner, IERC20(path[0]).balanceOf(address(this)));
            }

        }
    }

    function hedgeyPutSwap(address payable originalOwner, uint _p, uint assetAmount, address[] memory path) external payable nonReentrant {

        address[] memory _path = new address[](path.length - 1);
        for (uint i; i < path.length - 1; i++) {
            _path[i] = path[i];
        }
        bytes memory data = abi.encode(msg.sender, _p, _path, false);
        flashSwap(path[path.length - 2], path[path.length - 1], assetAmount, data);
        if(IHedgey(msg.sender).pymtCurrency() == weth) {
            uint wethBalance = IERC20(weth).balanceOf(address(this));
            IWETH(weth).withdraw(wethBalance);
            originalOwner.transfer(wethBalance);
        } else {
            SafeERC20.safeTransfer(IERC20(path[0]), originalOwner, IERC20(path[0]).balanceOf(address(this)));
        }

    }


}

