        if (!_isExcludedFromFee[sender] && !_isExcludedFromFee[recipient]) {
            require(amount <= maxTxAmount, "you are exceeding maxTxAmount");
        }

        if (recipient == pancakePair) {
            require(_includeInSell[sender], "ERC20:Not allowed to sell");

